<?php
namespace Tests\Feature;use App\Domain\Hunts\Data\HuntResult;use App\Domain\Hunts\HuntService;use App\Models\Character;use App\Models\CharacterItem;use App\Models\CharacterWallet;use App\Models\GoldTransaction;use App\Models\Hunt;use App\Models\User;use App\Models\Zone;use Database\Seeders\WorldCatalogSeeder;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;class HuntServiceTest extends TestCase{use RefreshDatabase;public function test_hunt_persists_snapshot_without_rewards_or_health_changes(){$this->seed(WorldCatalogSeeder::class);$c=Character::factory()->for(User::factory())->create();$zone=Zone::where('code','grey_oak_forest')->first();$before=$c->fresh()->toArray();$r=app(HuntService::class)->start($c,$zone);$this->assertInstanceOf(HuntResult::class,$r);$this->assertSame(1,Hunt::count());$this->assertSame($before,$c->fresh()->toArray());$this->assertSame(0,CharacterItem::count());$this->assertSame(0,CharacterWallet::count());$this->assertSame(0,GoldTransaction::count());$this->assertLessThanOrEqual($r->completedAt(),$r->startedAt());$hunt=Hunt::first();$old=$hunt->monster_name;$hunt->monster->update(['name'=>'Renamed']);$this->assertSame($old,$hunt->fresh()->monster_name);}public function test_detail_is_scoped_to_character_relation(){$this->seed(WorldCatalogSeeder::class);$a=Character::factory()->for(User::factory())->create();$b=Character::factory()->for(User::factory())->create();$h=app(HuntService::class)->start($a,Zone::where('code','grey_oak_forest')->first());$this->expectException(\Illuminate\Database\Eloquent\ModelNotFoundException::class);app(HuntService::class)->detail($b,$h->huntId());}}
